const MODO_PRUEBA = true;
const TEST_NUMBER = '573012661158';

const r = $json;
const first = String(r.nombre || '').trim().split(/\s+/)[0] || '';
const texto = String(r.plantilla)
  .replace(/\{\{\s*nombre\s*\}\}/g, first)
  .replace(/\s{2,}/g, ' ')
  .trim();

const t = Number(r.toques_outbound || 0);
const meses = t <= 0 ? 3 : (t === 1 ? 6 : 12);
const d = new Date();
d.setMonth(d.getMonth() + meses);
const prx = d.toISOString().slice(0, 10);

return { json: {
  telefono: r.telefono,
  numero_envio: MODO_PRUEBA ? TEST_NUMBER : r.telefono,
  nombre: r.nombre,
  tipificacion: r.tipificacion,
  texto,
  prx_contacto: prx,
  prueba: MODO_PRUEBA
} };
